#include<bits/stdc++.h>
using namespace std;
long long m,n;
struct node
{
    long long l,r,lson,rson;
    long long sum,cnt;
}t[6400010];
long long tot,v[100010],root[100010];
map<long long,long long> mp;
long long p[100010];
vector<long long> st[100010],ed[100010];
long long update(long long x,long long v,long long l,long long r,long long f)
{
    long long now=++tot;
    t[now]=t[x];
    t[now].cnt+=f;
    t[now].sum+=(::v[v])*f;
    if(l==r)
    {
        return now;
    }
    long long mid=(l+r)>>1;
    if(v<=mid)
    {
        t[now].lson=update(t[x].lson,v,l,mid,f);
    }
    else
    {
        t[now].rson=update(t[x].rson,v,mid+1,r,f);
    }
    return now;
}
long long query(long long x,long long l,long long r,long long k)
{
    if(l==r)
    {
        return t[x].sum/t[x].cnt*k;
    }
    long long p=t[t[x].lson].cnt,mid=(l+r)>>1;
    if(k<=p)
    {
        return query(t[x].lson,l,mid,k);
    }
    else
    {
        return t[t[x].lson].sum+query(t[x].rson,mid+1,r,k-p);
    }
}
int main()
{
    scanf("%lld%lld",&m,&n);
    long long tot11=0;
    for(long long i=1;i<=m;i++)
    {
        long long s,e;
        scanf("%lld%lld%lld",&s,&e,&p[i]);
        v[++tot11]=p[i];
        st[s].push_back(i);
        ed[e+1].push_back(i);
    }
    sort(v+1,v+1+tot11);
    tot11=unique(v+1,v+1+tot11)-v-1;
    for(long long i=1;i<=m;i++)
    {
        p[i]=lower_bound(v+1,v+1+tot11,p[i])-v;
    }
    for(long long i=1;i<=n;i++)
    {
        root[i]=root[i-1];
        for(long long j:st[i])
        {
            root[i]=update(root[i],p[j],1,tot11,1);
        }
        for(long long j:ed[i])
        {
            root[i]=update(root[i],p[j],1,tot11,-1);
        }
    }
    long long pre=1;
    for(long long i=1;i<=n;i++)
    {
        long long x,a,b,c;
        scanf("%lld%lld%lld%lld",&x,&a,&b,&c);
        long long k=1+(a*pre+b)%c;
        if(k>t[root[x]].cnt)
        {
            printf("%lld\n",pre=t[root[x]].sum);
            continue;
        }
        printf("%lld\n",pre=query(root[x],1,tot11,k));
    }
    return 0;
}
